import React from "react";
import "./test.css";

const typeDescriptions = {
  ENFP: "„აღმომჩენი“ - ენერგიული, კრეატიული და მხნე. უყვართ ახალი იდეები, ურთიერთობები და ადამიანების შთაგონება. გამოირჩევიან სხვების მხარდაჭერით, უჭუალო კომუნიკაციითა და აქვთ გადამდები ენერგეტიკა.",
  ISTJ: "„ლოჯისტიკოსი“ - პრაქტიკული, საიმედო და დეტალებზე ორიენტირებული ადამიანი არიან, რომლებიც აფასებენ სტრუქტურას, წესრიგსა და პასუხისმგებლობას. ყოველთვის ასრულებენ დანაპირებს.",
  INFJ: "„მრჩეველი, იდეალისტი“ - სულიერად მდიდარი, შემოქმედებითი, მზრუნველი და გულწრფელი ადამიანები არიან. აფასებენ ურთიერთობებს, შთააგონებენ სხვებსა  და არიან მოტივატორები. ",
  ESFP: "„პერფორმერი“ - ენერგიული, მეგობრული და უშუალო ადამიანები არიან, სიამოვნებას იღებენ სხვების გარემოცვაში ყოფნით, რადგან უყვართ ყურადღების ცენტრში ყოფნა. არიან სპონტანურები, მხიარულები და ოპტიმისტურები.",
  INFP: "„მედიატორი“ - სულიერად მგრძნობიარე, იდეალისტი, შემოქმედებითი და ემპათიური ადამიანები არიან. მნიშვნელობას ანიჭებენ ადამიანურ ღირებულებებს. გამოირჩევიან სპონტანური, ჰარმონიული ცხოვრების წესითა და განსაკუთრებულ ყურადღებას უთმობენ ოჯახსა და ახლო მეგობრებს. ",
  ESTJ: "„აღმსრულებელი, მმართველი“ - პრაქტიკული, პასუხისმგებლობით აღსასე, ორგანიზებული ადამიანები არიან, რომლებიც აფასებენ წესრიგს, სტრუქტურას და ტრადიციებს. მათ უყვართ მკაფიო წესები და მოქმედებენ გათვლილი გეგმით. პასუხისმგებლობით ეკიდებიან საკუთარ მოვალეობებსა და გამოირჩევიან ლიდერული თვისებებით. ",
  ENFJ: "„პროტაგონისტი“ - პასუხისმგებლობით აღჭურვილი, ენერგიული და ერთგული ადამიანები არიან, რომლებიც გამოირჩევიან კომუნიკაბელურობით, ძლიერი სოციალური ინტელექტით და სხვების მოტივირების უნარით. არიან კარგი ლედერები განსაკუთრებით გუნდური მუსაობისას, ხშირად იღებენ პასუხისმგებლობას ჯგუფის კეთილდღეობაზე. უყვართ როცა თავს გრძნობენ „საჭიროდ“.",
  ISFP: "„თავგადასავლების მოყვარული“ - მშვიდი, შემოქმედებითი და ბუნებაზე ორიენტირებული ადამიანია. უყვართ გამოცდილებით სწავლა და ცდილობენ მიიღონ სიამოვნება ცხოვრებისგან, ამიტომ ცდილობენ თავი აარიდონ კონფლიკტურ სიტუაციებს და ცდილობენ კომფირტი შეუქმნან გარშემომყოფებსაც.",
  ISTP: "პრაქტიკული, ანალიტიკური და დამოუკიდებელი.",
  ESFJ: "„კონსული“ - გულწრფელი, სანდო, სოციალური, დეტალებზე ორიენტირებული და მოსიყვარულე ადამიანები არიან,რომლებიც გამოირჩევიან გადაჭარბებული პასუხისმგებლობის გრძნობით, პრაქტიკულობით. ცდილობენ შექმნან ჰარმონიული გარემო მეგობრებისა თუ კოლეგების წრეში, ხშირად ითვალისწინებენ სხვების ინტერესებს.მგრძნობიარენი არიან კრიტიკისა და ცვილებებისადმი.",
  ENTJ: "„კომანდირი“ - თავდაჯერებულები, მიზანდასახულები, ამბიციური, სტრატეგიული და გავლენიანი, ბუნებით ლიდერი ადამიანები არიან. ხშირად გვევლინებიან ხელმძღვანელებად, დირექტორებად ან ორგანიზატორებად. ისინი სწრაფად იღებენ გადაწყვეტილებებს, ხედავენ დიდ სურათს და ეფექტურად მართავენ გუნდებს.",
